/// <summary>
/// Contract class for the Transactions by Operation Report in the ETGSPAIN model.
/// </summary>
[
SysOperationGroupAttribute('Parameters', "@ETGSPAINLabels:Parameters", '1'),
SysOperationGroupAttribute('ViewGroup', "@ETGSPAINLabels:View", '2')
]
public class ETGSPAINInventTransOperationContract
{
    FromDate                fromDate;
    ToDate                  toDate;
    boolean                 showItem;
    InventDimViewContract   inventDimViewContract;

}

